const listaGastosUpper = listaGastos.map(g => g.toUpperCase().trim());
const transaccionesSinGastos = transaccionesRango.filter(i => {
  const concepto = i.json.concepto?.toString().toUpperCase().trim() || '';
  return !listaGastosUpper.includes(concepto);
});

return transaccionesSinGastos;

