const libroMayor = $('GetParametrosNormalizados2').all();

const parsearFecha = (fechaStr) => {
  if (!fechaStr) return null;
  const str = fechaStr.toString().trim();

  if (/^\d+$/.test(str)) {
    const serial = parseInt(str);
    const ms = (serial - 25569) * 86400 * 1000;
    const fecha = new Date(ms);
    const offsetMs = fecha.getTimezoneOffset() * 60 * 1000;
    const fechaLocal = new Date(ms + offsetMs);
    return `${fechaLocal.getDate()}/${fechaLocal.getMonth() + 1}/${fechaLocal.getFullYear()}`;
  }

  return str;
};

return libroMayor.map(item => ({
